import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const PlayerPortal = ({ gameId, playerEmail }) => {
  const [game, setGame] = useState(null);
  const [playerRole, setPlayerRole] = useState('');
  const [currentRoundIndex, setCurrentRoundIndex] = useState(null);

  const api = process.env.REACT_APP_API_BASE_URL || 'http://localhost:5000';

  const loadGame = async () => {
    try {
      const response = await axios.get(`${api}/api/games/${gameId}`);
      const gameData = response.data;
      setGame(gameData);

      const normalizedEmail = playerEmail?.toLowerCase();
      const role =
        normalizedEmail === gameData.player1?.email?.toLowerCase()
          ? 'P1'
          : normalizedEmail === gameData.player2?.email?.toLowerCase()
          ? 'P2'
          : '';
      setPlayerRole(role);
      setCurrentRoundIndex(gameData.currentRound);

      console.log('Player Role:', role);
      console.log('Game Data:', gameData);

      const roundIndex = gameData.rounds?.length ? gameData.rounds.length - 1 : 0;
      const round = gameData?.rounds?.[roundIndex];
      console.log('Round Object:', round);
    } catch (error) {
      console.error('Error loading game:', error);
    }
  };

  useEffect(() => {
    if (gameId && playerEmail) {
      loadGame();
    }
  }, [gameId, playerEmail]);

  const handleStartNextRound = async () => {
    try {
      await axios.post(`${api}/api/games/${gameId}/start-round`);
      await loadGame();
    } catch (error) {
      console.error('Failed to start next round:', error);
      alert(error.response?.data?.error || 'Failed to start next round.');
    }
  };

  const handleChallenge = async (attribute) => {
    try {
      await axios.post(`${api}/api/games/${gameId}/challenge`, { attribute });
      console.log(`✔️ Challenge sent for attribute: ${attribute}`);
      loadGame();
    } catch (error) {
      console.error('Error challenging attribute:', error);
    }
  };

  console.log("🧪 Responding to:", `${api}/api/games/${gameId}/respond-turn`);

  const handleRespond = async (decision, useTTT = false) => {
    try {
      await axios.post(`${api}/api/games/${gameId}/respond-turn`, {
        decision,
        useTTT,
      });
      loadGame();
    } catch (error) {
      console.error('Error responding to challenge:', error);
    }
  };

  const roundIndex = game?.rounds?.length ? game.rounds.length - 1 : 0;
  const round = game?.rounds?.[roundIndex];
  const drawnCard = playerRole === 'P1' ? round?.C1 : round?.C2;

  console.log('Drawn Card:', drawnCard);

  const score = playerRole === 'P1' ? game?.player1Score : playerRole === 'P2' ? game?.player2Score : null;
  const isResolved = !!round?.winner;
  const isAttacker = game?.attacker === playerRole;
  const hasChallenged = !!round?.attribute;
  const canUseTTT = isAttacker && !game?.usedTTT?.[playerRole] &&
    ['Rare', 'Very Rare', 'Epic', 'Spectacular'].includes(round?.attackerCard?.rarity);

  console.log("⚠️ isResolved:", isResolved);
  console.log("⚠️ isAttacker:", isAttacker);
  console.log("⚠️ hasChallenged:", hasChallenged);
  console.log("⚠️ canUseTTT:", canUseTTT);

  const getExpectedAttacker = () => {
    if (!game || !game.rounds || game.rounds.length === 0) return '';
    const currentIndex = game.rounds.length;
    for (let i = currentIndex - 1; i >= 0; i--) {
      const prev = game.rounds[i];
      if (prev?.result !== 'push') {
        return i % 2 === 0 ? 'P2' : 'P1';
      }
    }
    return currentIndex % 2 === 0 ? 'P1' : 'P2';
  };

  const expectedAttacker = getExpectedAttacker();
  const canStartNextRound = isResolved && playerRole === expectedAttacker;

  if (!gameId || !playerEmail) return <RedirectForm />;

  return (
    <div style={{ padding: '2rem' }}>
      <h1>Welcome, {playerEmail}</h1>
      <h2>
        You are <strong>{playerRole === 'P1' ? 'Attacking' : playerRole === 'P2' ? 'Defending' : '...'}</strong>
      </h2>

      <button onClick={loadGame} style={{ marginBottom: '1rem' }}>
        🔄 Refresh Game Data
      </button>

      {!isResolved && isAttacker && !hasChallenged && (
        <div>
          <h3>Choose an attribute to challenge:</h3>
          <button onClick={() => handleChallenge('Aura')}>Aura</button>
          <button onClick={() => handleChallenge('Skill')}>Skill</button>
          <button onClick={() => handleChallenge('Stamina')}>Stamina</button>
          {canUseTTT && <button onClick={() => handleRespond('accept', true)}>Use TTT</button>}
        </div>
      )}

      {!isResolved && !isAttacker && hasChallenged && (
        <div>
          <h3>You’ve been challenged on {round.attribute}</h3>
          <button onClick={() => handleRespond('accept')}>Accept</button>
          <button onClick={() => handleRespond('reject')}>Reject</button>
        </div>
      )}

      {drawnCard ? (
        <div>
          <h3>Your Drawn Card</h3>
          <p><strong>{drawnCard.character}</strong> ({drawnCard.rarity})</p>
          <p>Aura: {drawnCard.Aura}</p>
          <p>Skill: {drawnCard.Skill}</p>
          <p>Stamina: {drawnCard.Stamina}</p>
          <p>Total Score: {drawnCard.Score}</p>
          {drawnCard.card && (
            <img
              src={`/textures/${drawnCard.card}`}
              alt={`${drawnCard.character} card`}
              style={{ maxWidth: '300px', marginTop: '1rem' }}
            />
          )}
        </div>
      ) : (
        <p>No card drawn yet this round.</p>
      )}

      {score && (
        <div style={{ marginTop: '2rem' }}>
          <h4>Your Current Score</h4>
          <p>Aura: {score.aura}</p>
          <p>Skill: {score.skill}</p>
          <p>Stamina: {score.stamina}</p>
        </div>
      )}

      {canStartNextRound && (
        <button onClick={handleStartNextRound} style={{ marginTop: '2rem' }}>
          ▶️ Start Next Round
        </button>
      )}
    </div>
  );
};

const RedirectForm = () => {
  const navigate = useNavigate();
  const [gameId, setGameId] = useState('');
  const [email, setEmail] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (gameId && email) {
      navigate(`/player?gameId=${encodeURIComponent(gameId)}&email=${encodeURIComponent(email)}`);
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{ padding: '2rem' }}>
      <h2>Enter Game Info</h2>
      <input
        type="text"
        placeholder="Game ID"
        value={gameId}
        onChange={(e) => setGameId(e.target.value)}
        style={{ display: 'block', marginBottom: '1rem' }}
      />
      <input
        type="email"
        placeholder="Your Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        style={{ display: 'block', marginBottom: '1rem' }}
      />
      <button type="submit">Enter Player Portal</button>
    </form>
  );
};

export default PlayerPortal;
